use data::*;

macro_rules! implies {
  ($lhs: expr, $rhs: expr) => {
    !$lhs || $rhs
  };
}

macro_rules! impliesL {
  ($lhs: expr, $rhs: expr) => {
    !$lhs | $rhs
  };
}

/** I-Assm: Integration constraint on msg_filter's incoming event data port input
  *
  * assume No_TopSecret_Input
  */
pub fn I_Assm_input(input: SNG_Data_Model::Message) -> bool
{
  input.security_level != SNG_Data_Model::SecurityLevel::TopSecret
}

/** I-Assm: Integration constraint on msg_filter's incoming event data port input
  *
  * assume No_TopSecret_Input
  */
pub fn I_Assm_Guard_input(input: Option<SNG_Data_Model::Message>) -> bool
{
  implies!(
    input.is_some(),
    I_Assm_input(input.unwrap())
  )
}

/** CEP-Pre: Compute Entrypoint Pre-Condition for msg_filter
  *
  * @param api_input incoming event data port
  */
pub fn compute_CEP_Pre(api_input: Option<SNG_Data_Model::Message>) -> bool
{
  // I-Assm-Guard: Integration constraints for msg_filter's incoming ports
  let r0: bool = I_Assm_Guard_input(api_input);

  return r0;
}
